mapper.select:
select

from `role` br
inner join `org` bo on br.org_id = bo.id and bo.deleted = 0 and bo.status = 1 and bo.audit_status = 2
where br.deleted = 0

    and br.status = #{ew.status}


    and br.code = #{ew.code}


    and br.name = #{ew.name}

and bo.id = #{ew.orgId}
order by br.modified_time desc

select
,
from `role` br inner join `org` bo on br.org_id = bo.id and bo.deleted = 0 and bo.status = 1 and bo.audit_status = 2 where br.deleted = 0 and br.id = #{id}
